// Minimal pino stub for test environments: forwards to console.
module.exports = function (opts) {
  const wrap = (fn) => (...args) => {
    try {
      if (args.length === 1 && typeof args[0] === 'object') {
        // preserve objects
        fn(JSON.stringify(args[0]));
      } else {
        fn(...args);
      }
    } catch (e) {
      // noop
    }
  };

  const logger = {
    info: wrap(console.log.bind(console)),
    error: wrap(console.error.bind(console)),
    warn: wrap(console.warn.bind(console)),
    debug: wrap(console.debug ? console.debug.bind(console) : console.log.bind(console)),
    child: () => logger
  };

  return logger;
};
